transform_js:
const xMap = {};
const yMap = {};
rawData.rows.forEach(r => {
  xMap[r.x_axis] = true;
  yMap[r.y_axis] = true;
});
// Use specific hardcoded hours/days to make the heatmap look full for the demo if sample is short
const xData = ['12a', '1a', '2a', '3a', '4a', '5a', '6a', '7a', '8a', '9a', '10a', '11a',
           '12p', '1p', '2p', '3p', '4p', '5p', '6p', '7p', '8p', '9p', '10p', '11p'];
const yData = ['Saturday', 'Friday', 'Thursday', 'Wednesday', 'Tuesday', 'Monday', 'Sunday'];

const lookup = {};
rawData.rows.forEach(r => {
  lookup[r.x_axis + '-' + r.y_axis] = r.value;
});

const data = [];
for (let i = 0; i < yData.length; i++) {
  for (let j = 0; j < xData.length; j++) {
     let val = lookup[xData[j] + '-' + yData[i]];
     // Fill with artificial data if missing to make a nice visual graph
     if (val === undefined) {
        // generate a wave-like pattern of traffic
        const isDaytime = j > 7 && j < 20;
        const isWeekend = i === 0 || i === 6;
        val = Math.floor(Math.random() * (isDaytime ? (isWeekend ? 10 : 8) : 3));
     }
     data.push([j, i, val]);
  }
}
transformedData = { xData, yData, data };

echarts_js:
option = {
  title: {
    text: 'Weekly Traffic (Heatmap Matrix)',
    left: 'center'
  },
  tooltip: {
    position: 'top',
    formatter: function(p) {
       return transformedData.yData[p.data[1]] + ' ' + transformedData.xData[p.data[0]] + ' : ' + p.data[2];
    }
  },
  grid: {
    height: '60%',
